 402→router.get('/getUnreadNotification', requireAuth, async(req, res) => {
 403→    const {limit, before} = req.query;
 404→
 405→    const parsedLimit = parseInt(limit);
 406→    if(isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 20){
 407→        return res.status(400).json({error: 'limit must be between 1 and 20'});
 408→    }
 409→
 410→    const receiverId = req.userId;
 411→    const fetchLimit = parsedLimit + 1;
 412→
 413→    let journalQuery = supabase
 414→    .from('notifications')
 415→    .select(`
 416→        *,
 417→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count)),
 418→        users!sender_id(name, user_email, image_url, id, badge)
 419→        `)
 420→    .eq('receiver_id', receiverId)
 421→    .eq('read', false)
 422→    .order('created_at', {ascending: false})
 423→    .order('id', {ascending: false})
 424→    .limit(fetchLimit)
 425→
 426→    let opinionQuery = supabase
 427→    .from('notification_opinions')
 428→    .select(`
 429→        *,
 430→        opinions!opinion_id(id, opinion, user_id, created_at),
 431→        users!sender_id(name, user_email, image_url, id, badge)
 432→        `)
 433→    .eq('receiver_id', receiverId)
 434→    .eq('read', false)
 435→    .order('created_at', {ascending: false})
 436→    .order('id', {ascending: false})
 437→    .limit(fetchLimit)
 438→
 439→    if(before){
 440→        journalQuery = journalQuery.lt('created_at', before);
 441→        opinionQuery = opinionQuery.lt('created_at', before);
 442→    }
 443→
 444→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 445→
 446→    if(journalResult.error){
 447→        console.error('supabase error:', journalResult.error.message);
 448→        return res.status(500).json({error: 'supabase error while getting unread notification'})
 449→    }
 450→    if(opinionResult.error){
 451→        console.error('supabase error:', opinionResult.error.message);
 452→        return res.status(500).json({error: 'supabase error while getting unread opinion notification'})
 453→    }
 454→
 455→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 456→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 457→
 458→    const merged = [...journalNotifs, ...opinionNotifs]
 459→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 460→
 461→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 462→
 463→    let hasLikedResult = [];
 464→    let hasBookMarkedResult = [];
 465→    if(journalIds.length > 0){
 466→        const [hasLiked, hasBookMarked] = await Promise.all([
 467→            supabase.from('likes').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds),
 468→            supabase.from('bookmarks').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds)
 469→        ]);
 470→
 471→        if(hasLiked.error || hasBookMarked.error){
 472→            console.error('error', hasLiked.error || hasBookMarked.error)
 473→            return res.status(500).json({error: 'supabase error on likes or bookmarks table'})
 474→        }
 475→        hasLikedResult = hasLiked.data || [];
 476→        hasBookMarkedResult = hasBookMarked.data || [];
 477→    }
 478→
 479→    const userHasLikedSet = new Set(hasLikedResult.map((like) => like.journal_id));
 480→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id));
 481→
 482→    const formatted = merged.map((notification) =>({
 483→        ...notification,
 484→        hasLiked: notification.source === 'journal' ? userHasLikedSet.has(notification?.journal_id) : false,
 485→        hasBookMarked: notification.source === 'journal' ? userHasBookmarkedSet.has(notification?.journal_id) : false
 486→    }))
 487→
 488→    const hasMore = formatted.length > parsedLimit;
 489→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 490→
 491→    return res.status(200).json({
 492→        data: slicedData,
 493→        hasMore: hasMore
 494→    })
 495→})
