  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import useUniverseCamera from './hooks/useUniverseCamera';
  7→import useCosmicGravity from './hooks/useCosmicGravity';
  8→import DeepSpaceLayer from './layers/DeepSpaceLayer';
  9→import MidGalaxyLayer from './layers/MidGalaxyLayer';
 10→import InteractiveLayer from './layers/InteractiveLayer';
 11→import UniverseMinimap from './components/UniverseMinimap';
 12→import { extractSnippet, userHomeCoords } from './utils/starUtils';
 13→import { handleClickProfile } from '../../../helpers/handleClicks';
 14→import styles from './Universe.module.css';
 15→
 16→const Universe = () => {
 17→    const navigate = useNavigate();
 18→    const { user } = useAuth();
 19→    const userId = user?.userData?.[0]?.id || null;
 20→
 21→    const debounceRef = useRef(null);
 22→    const [posts, setPosts] = useState(new Map());
 23→    const [selectedPost, setSelectedPost] = useState(null);
 24→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 25→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 26→    const [pulsingId, setPulsingId] = useState(null);
 27→    // null = still loading, true/false = resolved
 28→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 29→
 30→    // Galaxy gravity state
 31→    const [centroids, setCentroids] = useState([]);
 32→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 33→    const [similarPairs, setSimilarPairs] = useState([]);
 34→    const [starPulls, setStarPulls] = useState([]);
 35→
 36→    const {
 37→        stageRef,
 38→        stageSize,
 39→        camera,
 40→        zoom,
 41→        isDragging,
 42→        centerWorld,
 43→        getLayerProps,
 44→        getViewportBounds,
 45→        stageEvents,
 46→        flyTo,
 47→        isFlying,
 48→    } = useUniverseCamera(userId, hasOwnPosts);
 49→
 50→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 51→    const showTitles = zoom > 0.5;
 52→
 53→    // Build centroid position map for gravity hook
 54→    const centroidPositions = useMemo(() => {
 55→        const map = new Map();
 56→        for (const c of centroids) {
 57→            if (c.galaxy_x != null && c.galaxy_y != null) {
 58→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
 59→            }
 60→        }
 61→        return map;
 62→    }, [centroids]);
 63→
 64→    // Client-side Gravity B simulation
 65→    const { positions: gravityPositions } = useCosmicGravity(postArray, starPulls, centroidPositions);
 66→
 67→    // Debounced fetch on camera/zoom change
 68→    useEffect(() => {
 69→        if (debounceRef.current) clearTimeout(debounceRef.current);
 70→
 71→        debounceRef.current = setTimeout(async () => {
 72→            const bounds = getViewportBounds();
 73→            try {
 74→                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
 75→                if (result?.data) {
 76→                    setPosts(prev => {
 77→                        const next = new Map(prev);
 78→                        for (const post of result.data) {
 79→                            next.set(post.id, post);
 80→                        }
 81→                        return next;
 82→                    });
 83→                    // Check if any returned posts belong to this user
 84→                    if (userId && hasOwnPosts === null) {
 85→                        const ownsAny = result.data.some(p =>
 86→                            (p.users?.id ?? p.user_id) === userId
 87→                        );
 88→                        setHasOwnPosts(ownsAny);
 89→                    }
 90→                }
 91→                // Update gravity data from server
 92→                if (result?.centroids) setCentroids(result.centroids);
 93→                if (result?.edges) setGalaxyEdges(result.edges);
 94→                if (result?.similarPairs) setSimilarPairs(result.similarPairs);
 95→                if (result?.starPulls) setStarPulls(result.starPulls);
 96→            } catch (err) {
 97→                console.error('Failed to fetch universe posts:', err);
 98→            }
 99→        }, 400);
100→
101→        return () => {
102→            if (debounceRef.current) clearTimeout(debounceRef.current);
103→        };
104→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
105→
106→    const handleStarClick = useCallback((post) => {
107→        if (isFlying.current) return;
108→        setSelectedPost(post);
109→        setSelectedGalaxy(null);
110→        setGalaxyProfile(null);
111→        const grav = gravityPositions?.get(post.id);
112→        const x = grav?.x ?? post.display_x ?? post.universe_x;
113→        const y = grav?.y ?? post.display_y ?? post.universe_y;
114→        flyTo(x, y, 1.2, () => {
115→            setPulsingId(post.id);
116→            setTimeout(() => setPulsingId(null), 700);
117→        });
118→    }, [flyTo, isFlying, gravityPositions]);
119→
120→    const handleGalaxyClick = useCallback(async (galaxy) => {
121→        if (isFlying.current) return;
122→        setSelectedGalaxy(galaxy);
123→        setSelectedPost(null);
124→        setGalaxyProfile(null);
125→
126→        // Zoom into the galaxy
127→        flyTo(galaxy.x, galaxy.y, 0.8);
128→
129→        try {
130→            const data = await getUserData(galaxy.userId);
131→            const profile = data?.userData?.[0] || null;
132→            setGalaxyProfile(profile);
133→        } catch (err) {
134→            console.error('Failed to fetch galaxy profile:', err);
135→        }
136→    }, [flyTo, isFlying]);
137→
138→    const handleReadPost = useCallback(() => {
139→        if (!selectedPost) return;
140→        navigate(`/home/post/${selectedPost.id}`);
141→    }, [selectedPost, navigate]);
142→
143→    const handleMinimapNavigate = useCallback((worldX, worldY) => {
144→        flyTo(worldX, worldY);
145→    }, [flyTo]);
146→
147→    // Derive one label per unique user (galaxy) — use centroid positions when available
148→    const galaxies = useMemo(() => {
149→        const seen = new Map();
150→        for (const post of postArray) {
151→            const uid = post.users?.id ?? post.user_id;
152→            if (!uid || seen.has(uid)) continue;
153→            const centroidPos = centroidPositions.get(uid);
154→            const home = centroidPos || userHomeCoords(uid);
155→            seen.set(uid, {
156→                userId: uid,
157→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
158→                x: home.x,
159→                y: home.y,
160→            });
161→        }
162→        return Array.from(seen.values());
163→    }, [postArray, centroidPositions]);
164→
165→    return (
166→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
167→            <button className={styles.backButton} onClick={() => navigate('/home')}>
168→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
169→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
170→                </svg>
171→                Back
172→            </button>
173→
174→            <div className={styles.coordsLabel}>
175→                {centerWorld.x}, {centerWorld.y}
176→            </div>
177→
178→            <Stage
179→                ref={stageRef}
180→                width={stageSize.width}
181→                height={stageSize.height}
182→                {...stageEvents}
183→            >
184→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
185→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
186→                <InteractiveLayer
187→                    layerProps={getLayerProps(1.0)}
188→                    posts={postArray}
189→                    galaxies={galaxies}
190→                    zoom={zoom}
191→                    showTitles={showTitles}
192→                    pulsingId={pulsingId}
193→                    onStarClick={handleStarClick}
194→                    onGalaxyClick={handleGalaxyClick}
195→                    gravityPositions={gravityPositions}
196→                    similarPairs={similarPairs}
197→                    galaxyEdges={galaxyEdges}
198→                />
199→            </Stage>
200→
201→            <UniverseMinimap
202→                galaxies={galaxies}
203→                camera={camera}
204→                zoom={zoom}
205→                stageSize={stageSize}
206→                onNavigate={handleMinimapNavigate}
207→            />
208→
209→            {selectedGalaxy && galaxyProfile && (
210→                <div className={styles.galaxyPreviewPanel}>
211→                    <button
212→                        className={styles.galaxyPreviewClose}
213→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
214→                    >
215→                        &times;
216→                    </button>
217→                    <div
218→                        className={styles.galaxyPreviewBg}
219→                        style={galaxyProfile.background || {}}
220→                    />
221→                    <div className={styles.galaxyPreviewContent}>
222→                        <img
223→                            className={styles.galaxyPreviewAvatar}
224→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
225→                            alt=""
226→                        />
227→                        <div className={styles.galaxyPreviewHeading}>
228→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
229→                        </div>
230→                        {galaxyProfile.bio && (
231→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
