144→router.get('/journals/search', searchJournalsController);
145→router.get('/universe/posts', optionalAuth, async(req, res) => {
146→    const {minX, maxX, minY, maxY, limit} = req.query;
147→
148→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 200, 1), 500);
149→
150→    if(!minX || !maxX || !minY || !maxY){
151→        return res.status(400).json({error: 'minX, maxX, minY, maxY are required'});
152→    }
153→
154→    const fMinX = parseFloat(minX);
155→    const fMaxX = parseFloat(maxX);
156→    const fMinY = parseFloat(minY);
157→    const fMaxY = parseFloat(maxY);
158→
159→    try {
160→        // 1. Posts via RPC (uses COALESCE for settled/universe coords)
161→        const { data: rpcPosts, error: rpcError } = await supabase.rpc('get_universe_posts_viewport', {
162→            vp_min_x: fMinX, vp_max_x: fMaxX,
163→            vp_min_y: fMinY, vp_max_y: fMaxY,
164→            max_count: parsedLimit
165→        });
166→
167→        // Fallback to old query if RPC doesn't exist yet
