router.get('/universe/posts', optionalAuth, async(req, res) => {
    const {minX, maxX, minY, maxY, limit} = req.query;

    const parsedLimit = Math.min(Math.max(parseInt(limit) || 200, 1), 500);

    if(!minX || !maxX || !minY || !maxY){
        return res.status(400).json({error: 'minX, maxX, minY, maxY are required'});
    }

    const fMinX = parseFloat(minX);
    const fMaxX = parseFloat(maxX);
    const fMinY = parseFloat(minY);
    const fMaxY = parseFloat(maxY);

    try {
        // 1. Posts via RPC (uses COALESCE for settled/universe coords)
        const { data: rpcPosts, error: rpcError } = await supabase.rpc('get_universe_posts_viewport', {
            vp_min_x: fMinX, vp_max_x: fMaxX,
            vp_min_y: fMinY, vp_max_y: fMaxY,
            max_count: parsedLimit
        });

        // Fallback to old query if RPC doesn't exist yet
        let posts;
        if (rpcError) {
            const { data: fallbackData, error: fallbackError } = await supabase
                .from('journals')
                .select('id, title, content, post_type, canvas_doc, created_at, universe_x, universe_y, users(id, name, image_url, badge), likes(count)')
                .eq('privacy', 'public')
                .not('universe_x', 'is', null)
                .not('universe_y', 'is', null)
                .gte('universe_x', fMinX)
                .lte('universe_x', fMaxX)
                .gte('universe_y', fMinY)
                .lte('universe_y', fMaxY)
                .limit(parsedLimit);

            if (fallbackError) {
                console.error('error fetching universe posts:', fallbackError.message);
                return res.status(500).json({ error: 'error fetching universe posts' });
            }
            posts = fallbackData || [];
        } else {
            posts = rpcPosts || [];
        }

        // 2. Galaxy centroids in/near viewport (with padding)
        let centroids = [];
        try {
            const { data } = await supabase
                .from('galaxy_centroids')
                .select('user_id, galaxy_x, galaxy_y, post_count')
                .not('galaxy_x', 'is', null)
                .gte('galaxy_x', fMinX - 1000).lte('galaxy_x', fMaxX + 1000)
                .gte('galaxy_y', fMinY - 1000).lte('galaxy_y', fMaxY + 1000);
            centroids = data || [];
        } catch (_) {}

        // 3. Galaxy edges for visible galaxies
        const visibleUserIds = [...new Set(centroids.map(c => c.user_id))];
        let edges = [];
        if (visibleUserIds.length > 0) {
            try {
                const { data: edgeData } = await supabase
                    .from('galaxy_edges')
                    .select('user_a, user_b, similarity')
                    .or(`user_a.in.(${visibleUserIds.join(',')}),user_b.in.(${visibleUserIds.join(',')})`)
                    .gte('similarity', 0.3);
                edges = edgeData || [];
            } catch (_) {}
        }

        // 4. Similar post pairs for semantic bridges
        const postIds = posts.map(p => p.id);
        let similarPairs = [];
        if (postIds.length > 1 && postIds.length <= 500) {
            try {
                const { data: pairData } = await supabase.rpc('find_similar_post_pairs', {
                    post_ids: postIds, threshold: 0.9, max_pairs: 50
                });
                similarPairs = pairData || [];
            } catch (_) {}
        }

        // 5. Star-to-galaxy pulls for client-side Gravity B animation
        let starPulls = [];
        if (postIds.length > 0) {
            try {
                const { data: pullData } = await supabase.rpc('get_star_galaxy_pulls', {
                    post_ids: postIds, min_similarity: 0.4, max_pulls: 500
                });
                starPulls = pullData || [];
            } catch (_) {}
        }

        return res.status(200).json({
            data: posts,
            centroids,
            edges,
            similarPairs,
            starPulls
        });
    } catch (err) {
        console.error('error in universe/posts:', err?.message || err);
        return res.status(500).json({ error: 'error fetching universe posts' });
    }
});

